def slerp_task_vectors(base_sd, sd_a, sd_b, t=0.5, lam=1.0):
    """
    SLERP in task vector space.
    Interpolates between tau_A and tau_B, then adds to the base model.
    lam: overall scaling of the merged task vector
    """
    tau_a = {k: sd_a[k].float() - base_sd[k].float() for k in base_sd}
    tau_b = {k: sd_b[k].float() - base_sd[k].float() for k in base_sd}

    # SLERP between the task vectors
    tau_merged = {}
    for k in base_sd:
        if tau_a[k].numel() == 1:
            tau_merged[k] = (1 - t) * tau_a[k] + t * tau_b[k]
        else:
            tau_merged[k] = slerp(tau_a[k], tau_b[k], t)

    # Apply merged task vector at strength lambda
    return {k: base_sd[k].float() + lam * tau_merged[k] for k in base_sd}

def recursive_slerp_merge(state_dicts, t=0.5):
    """
    Merge N models by recursively applying SLERP pairwise.
    state_dicts: list of state dicts (N >= 2)
    t:           interpolation factor applied at each step
    """
    if len(state_dicts) == 1:
        return state_dicts[0]
    if len(state_dicts) == 2:
        return slerp_merge(state_dicts[0], state_dicts[1], t)

    # Merge first two, then merge result with the rest
    merged_first = slerp_merge(state_dicts[0], state_dicts[1], t)
    return recursive_slerp_merge([merged_first] + state_dicts[2:], t)

